document.addEventListener('DOMContentLoaded', () => {
    'use strict'

    initCardsActions();
})

const initCardsActions = () => {
    document.addEventListener('click', (e) => {
        const swiperButtons = e.target.closest('.swiper-buttons');
        if (swiperButtons) {
            return;
        }

        if (e.target.closest('button')) {
            return;
        }

        const card = e.target.closest('.unit-card');
        if (card) {
            e.stopPropagation();
            let cardDetailsUrl = card.querySelector('.unit-card-info-buttons a').getAttribute('href');
            if (!cardDetailsUrl) return;

            window.location.href = cardDetailsUrl;
        }


    })
}